import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import { AuthProvider } from './context/AuthContext';
import { CartProvider } from './context/CartContext';
import { ToastProvider } from './context/ToastContext';
import { ProtectedRoute, AdminRoute } from './components/ProtectedRoute';

import Navbar        from './components/Navbar';
import Home          from './pages/Home';
import Login         from './pages/Login';
import Register      from './pages/Register';
import ForgotPassword from './pages/ForgotPassword';
import Books         from './pages/Books';
import BookDetail    from './pages/BookDetail';
import Dashboard     from './pages/Dashboard';
import Cart          from './pages/Cart';
import NotFound      from './pages/NotFound';
import OAuthSuccess  from './pages/OAuthSuccess'; // ✅ NEW

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        {/* CartProvider wraps inside AuthProvider so it can read user from AuthContext */}
        <CartProvider>
          <ToastProvider>
            <Navbar />
            <Routes>
              {/* Public routes */}
              <Route path="/"               element={<Home />} />
              <Route path="/login"          element={<Login />} />
              <Route path="/register"       element={<Register />} />
              <Route path="/forgot-password" element={<ForgotPassword />} />
              <Route path="/books"          element={<Books />} />
              <Route path="/books/:id"      element={<BookDetail />} />

              {/* ✅ NEW: Google OAuth callback route */}
              {/* Backend's OAuth2SuccessHandler redirects here after Google login */}
              <Route path="/oauth-success"  element={<OAuthSuccess />} />

              {/* Cart — shows login prompt if not authenticated */}
              <Route path="/cart" element={<Cart />} />

              {/* Protected routes (any logged-in user) */}
              <Route path="/dashboard" element={
                <ProtectedRoute>
                  <Dashboard />
                </ProtectedRoute>
              } />

              {/* 404 */}
              <Route path="*" element={<NotFound />} />
            </Routes>
          </ToastProvider>
        </CartProvider>
      </AuthProvider>
    </BrowserRouter>
  );
}
